FormScriptItem.Script:
var CallServerSide = function () {

	VV.Form.ShowLoadingPanel();
	//This gets all of the form fields.
	var formData = VV.Form.getFormDataCollection();

	//Following will prepare the collection and send with call to server side script.
	var data = JSON.stringify(formData);
	var requestObject = $.ajax({
		type: "POST",
		url: VV.BaseAppUrl + 'api/v1/' + VV.CustomerAlias + '/' + VV.CustomerDatabaseAlias + '/scripts?name=ValidateHoneypot',
		contentType: "application/json; charset=utf-8",
		data: data,
		success: '',
		error: ''
	});

	return requestObject;
};

VV.Form.ShowLoadingPanel();

$.when(
	CallServerSide()
).always(function (resp) {
	console.log(resp);
	VV.Form.HideLoadingPanel();
	var messageData = '';
	if (typeof (resp.status) != 'undefined') {
		messageData = "A status code of " + resp.status + " returned from the server.  There is a communication problem with the  web servers.  If this continues, please contact the administrator and communicate to them this message and where it occurred.";
		VV.Form.Global.DisplayMessaging(messageData);
	}
	else if (typeof (resp.statusCode) != 'undefined') {
		messageData = "A status code of " + resp.statusCode + " with a message of '" + resp.errorMessages[0].message + "' returned from the server.  This may mean that the servers to run the business logic are not available.";
		VV.Form.Global.DisplayMessaging(messageData);
	}
	else if (resp.meta.status == '200') {
		if (resp.data[0] != 'undefined') {
			if (resp.data[0] == 'Success') {
								alert(resp.data[1]);
			} else if (resp.data[0] == 'Error') {
				messageData = 'An error was encountered. ' + resp.data[1];

				alert(messageData);
				return false
			} else {
				messageData = 'An unhandled response occurred when calling ValidateCaptcha. The form will not save at this time.  Please try again or communicate this issue to support.';
				VV.Form.HideLoadingPanel();
				//VV.Form.Global.DisplayMessaging(messageData);
				alert(messageData);
				return false
			}
		}
		else {
			messageData = 'The status of the response returned as undefined.';
			VV.Form.HideLoadingPanel();
			//VV.Form.Global.DisplayMessaging(messageData);
			alert(messageData);
			return false
		}
	}
	else {
		messageData = "The following unhandled response occurred while attempting to retrieve data on the the server side get data logic." + resp.data.error + '<br>';
		VV.Form.HideLoadingPanel();
		//VV.Form.Global.DisplayMessaging(messageData);
		alert(messageData);
		return false
	}
});

var start = VV.Form.GetFieldValue('StartTime');
var end = Date.now();
var elapsedTime = (end - start) / 1000;

if(elapsedTime  > seconds){
  return true;
} else {
  return false;
}

(function SetHoneypot() {
  // Remove fields from tab focus
  document.getElementById("Password").style.tabindex = "-1";
  document.getElementById("StartTime").style.tabindex = "-1";
  // Field value
  document.getElementById("Password").style.value = "1";
  // Disable autofilling
  document.getElementById("Password").style.autocomplete = "off";
  // Save load time
  var startTime = Date.now();
  VV.Form.SetFieldValue('StartTime', startTime, false)
})()

if(VV.Form.Template.TimeGate(3)){
  VV.Form.Template.CallToValidateHoneypot()
}else{
 alert("Please, try again after a few seconds.");
}
